import{_ as s,c as a,o as n,a as l}from"./app.204b65b3.js";const F=JSON.parse('{"title":"05.分组查询","description":"","frontmatter":{},"headers":[{"level":2,"title":"1. 介绍","slug":"_1-介绍","link":"#_1-介绍","children":[]},{"level":2,"title":"2. 语法","slug":"_2-语法","link":"#_2-语法","children":[]},{"level":2,"title":"3. 简单分组函数","slug":"_3-简单分组函数","link":"#_3-简单分组函数","children":[]},{"level":2,"title":"2. 添加筛选条件","slug":"_2-添加筛选条件","link":"#_2-添加筛选条件","children":[]},{"level":2,"title":"3. 添加复杂的筛选条件","slug":"_3-添加复杂的筛选条件","link":"#_3-添加复杂的筛选条件","children":[]},{"level":2,"title":"4. 分组查询特点","slug":"_4-分组查询特点","link":"#_4-分组查询特点","children":[]},{"level":2,"title":"5. 按表达式或函数分组","slug":"_5-按表达式或函数分组","link":"#_5-按表达式或函数分组","children":[]},{"level":2,"title":"6. 按多个字段分组","slug":"_6-按多个字段分组","link":"#_6-按多个字段分组","children":[]},{"level":2,"title":"7. 分组查询添加排序","slug":"_7-分组查询添加排序","link":"#_7-分组查询添加排序","children":[]}],"relativePath":"articles/02-后端/Mysql/05.分组查询.md"}'),p={name:"articles/02-后端/Mysql/05.分组查询.md"},e=l(`<h1 id="_05-分组查询" tabindex="-1">05.分组查询 <a class="header-anchor" href="#_05-分组查询" aria-hidden="true">#</a></h1><h2 id="_1-介绍" tabindex="-1">1. 介绍 <a class="header-anchor" href="#_1-介绍" aria-hidden="true">#</a></h2><p>引入：查询每个部门的平均工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">-- 以前写法：求的是总平均工资。</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">AVG</span><span style="color:#A6ACCD;">(salary) </span><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">-- 正确写法</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">AVG</span><span style="color:#A6ACCD;">(salary), department_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> department_id;</span></span>
<span class="line"></span></code></pre></div><h2 id="_2-语法" tabindex="-1">2. 语法 <a class="header-anchor" href="#_2-语法" aria-hidden="true">#</a></h2><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> 分组函数, 列 </span><span style="color:#676E95;font-style:italic;">--列要求出现在 group by 的后面</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> 表</span></span>
<span class="line"><span style="color:#A6ACCD;">[WHERE 筛选条件]</span></span>
<span class="line"><span style="color:#A6ACCD;">[GROUP BY 分组的列表]</span></span>
<span class="line"><span style="color:#A6ACCD;">[ORDER BY 列|分组函数];</span></span>
<span class="line"></span></code></pre></div><p>注意： 查询列表必须特殊，要求是分组函数和 <code>group by</code> 后出现的字段。</p><blockquote><p>一般出现 “每个”、“各个”、“每一个”、“所有” 等词语，都是要进行分组查询，并且这些词的后紧接的就是 <code>ORDER BY</code> 后的内容。</p></blockquote><h2 id="_3-简单分组函数" tabindex="-1">3. 简单分组函数 <a class="header-anchor" href="#_3-简单分组函数" aria-hidden="true">#</a></h2><p>案例一：查询每个工种的最高工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MAX</span><span style="color:#A6ACCD;">(salary), job_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> job_id;</span></span>
<span class="line"></span></code></pre></div><p>案例二：查询每个位置上的部门个数</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">COUNT</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">),location_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> departments</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> location_id;</span></span>
<span class="line"></span></code></pre></div><h2 id="_2-添加筛选条件" tabindex="-1">2. 添加筛选条件 <a class="header-anchor" href="#_2-添加筛选条件" aria-hidden="true">#</a></h2><p>案例 1：普询邮箱中包含 a 字符的，每个部门的平均工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">AVG</span><span style="color:#A6ACCD;">(salary), department_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> email </span><span style="color:#F78C6C;">like</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">%a%</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> department_id;</span></span>
<span class="line"></span></code></pre></div><p>案例 2:查询有奖金的每个领导手下员工的最高工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MAX</span><span style="color:#A6ACCD;">(salary), manager_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> commission_pct </span><span style="color:#F78C6C;">IS NOT NULL</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> manager_id;</span></span>
<span class="line"></span></code></pre></div><h2 id="_3-添加复杂的筛选条件" tabindex="-1">3. 添加复杂的筛选条件 <a class="header-anchor" href="#_3-添加复杂的筛选条件" aria-hidden="true">#</a></h2><p>添加分组后的筛选：<code>HAVING</code></p><p>案例 1: 查询哪个部门的员工个数&gt;2</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">COUNT</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">), department_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> department_id</span></span>
<span class="line"><span style="color:#F78C6C;">HAVING</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">COUNT</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">2</span><span style="color:#A6ACCD;">;</span></span>
<span class="line"></span></code></pre></div><p>案例 2：查询每个工种有奖金的员工的最高工资&gt;12000 的工种编号和最高工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">-- 1. 查询每个工种有奖金的员工的最高工资</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MAX</span><span style="color:#A6ACCD;">(salary),job_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> commission_pct </span><span style="color:#F78C6C;">IS NOT NULL</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> job_id;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">-- 2. 根据1结果继续筛选，最高工资&gt;12000</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MAX</span><span style="color:#A6ACCD;">(salary),job_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> commission_pct </span><span style="color:#F78C6C;">IS NOT NULL</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> job_id</span></span>
<span class="line"><span style="color:#F78C6C;">HAVING</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MAX</span><span style="color:#A6ACCD;">(salary)</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">12000</span><span style="color:#A6ACCD;">;</span></span>
<span class="line"></span></code></pre></div><p>案例 3:查询领导编号&gt;102 的每个领导手下的最低工资&gt;5000 的领导编号</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MIN</span><span style="color:#A6ACCD;">(salary), manager_id</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> manager_id</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">102</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> manager_id</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">HAVING</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MIN</span><span style="color:#A6ACCD;">(salary)</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">5000</span><span style="color:#A6ACCD;">;</span></span>
<span class="line"></span></code></pre></div><h2 id="_4-分组查询特点" tabindex="-1">4. 分组查询特点 <a class="header-anchor" href="#_4-分组查询特点" aria-hidden="true">#</a></h2><p>分组查询中的筛选条件分为两类：</p><table><thead><tr><th>分类</th><th>数据源</th><th>关键字</th><th>位置</th></tr></thead><tbody><tr><td>分组前筛选</td><td>原始表</td><td><code>WHERE</code></td><td><code>GROUP BY</code></td></tr><tr><td>子句的前面</td><td></td><td></td><td></td></tr><tr><td>分组后筛选</td><td>分组后的结果集</td><td><code>HAVING</code></td><td><code>GROUP BY</code></td></tr><tr><td>子句的后面</td><td></td><td></td><td></td></tr></tbody></table><ol><li>分组函数做条件肯定是放在 <code>having</code> 子句中</li><li>能用分组前筛选的优先使用分组前筛选（性能好）</li><li><code>GROUP BY</code> 子句支持单个字段分组，多个字段分组（多个字段之间用逗号隔开，没有顺序要求）</li><li>排序查询放在最后</li></ol><h2 id="_5-按表达式或函数分组" tabindex="-1">5. 按表达式或函数分组 <a class="header-anchor" href="#_5-按表达式或函数分组" aria-hidden="true">#</a></h2><p>案例: 按员工姓名的长度分组，查询每一组的员工个数，筛选员工个数&gt;5</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">-- a. 查询每个长度的员工个数</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">COUNT</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">), </span><span style="color:#F78C6C;">LENGTH</span><span style="color:#A6ACCD;">(last_name) </span><span style="color:#F78C6C;">AS</span><span style="color:#A6ACCD;"> len_name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">LENGTH</span><span style="color:#A6ACCD;">(last_name)</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">-- b. 添加筛选条件</span></span>
<span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">COUNT</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">) c, </span><span style="color:#F78C6C;">LENGTH</span><span style="color:#A6ACCD;">(last_name) </span><span style="color:#F78C6C;">AS</span><span style="color:#A6ACCD;"> len_name</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> len_name</span></span>
<span class="line"><span style="color:#F78C6C;">HAVING</span><span style="color:#A6ACCD;"> c</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">5</span><span style="color:#A6ACCD;">;</span></span>
<span class="line"></span></code></pre></div><h2 id="_6-按多个字段分组" tabindex="-1">6. 按多个字段分组 <a class="header-anchor" href="#_6-按多个字段分组" aria-hidden="true">#</a></h2><p>案例: 查询每个部门每个工种的员工的平均工资</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">AVG</span><span style="color:#A6ACCD;">(salary), department_id, job_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> department_id, job_id;</span></span>
<span class="line"></span></code></pre></div><h2 id="_7-分组查询添加排序" tabindex="-1">7. 分组查询添加排序 <a class="header-anchor" href="#_7-分组查询添加排序" aria-hidden="true">#</a></h2><p>案例: 查询每个部门每个工种的员工的平均工资，并且按平均工资的高低排列 排序查询放在最后</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#F78C6C;">SELECT</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">AVG</span><span style="color:#A6ACCD;">(salary) a, department_id, job_id</span></span>
<span class="line"><span style="color:#F78C6C;">FROM</span><span style="color:#A6ACCD;"> employees</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> department_id </span><span style="color:#F78C6C;">IS NOT NULL</span></span>
<span class="line"><span style="color:#F78C6C;">GROUP BY</span><span style="color:#A6ACCD;"> department_id, job_id</span></span>
<span class="line"><span style="color:#F78C6C;">HAVING</span><span style="color:#A6ACCD;"> a</span><span style="color:#89DDFF;">&gt;</span><span style="color:#F78C6C;">10000</span></span>
<span class="line"><span style="color:#F78C6C;">ORDER BY</span><span style="color:#A6ACCD;"> a </span><span style="color:#F78C6C;">DESC</span><span style="color:#A6ACCD;">;</span></span>
<span class="line"></span></code></pre></div>`,39),o=[e];function t(c,C,r,i,y,A){return n(),a("div",null,o)}const D=s(p,[["render",t]]);export{F as __pageData,D as default};
